INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-00149', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡單眼視覺法（monovision）之敘述，下列何者錯誤？', '["單眼視覺法可避免在配戴多焦點隱形眼鏡時所產的重影（ghostimages）和視力波動（fluctuatingvision） 等現象", "配戴者的年齡和加入度（addpower）是單眼視覺法成功的預測因素，其加入度為+1.25至+2.00的配戴者 成功率很高", "有內斜位眼位的配戴者，配戴單眼視覺法會影響立體視覺", "透過單眼視覺法矯正，遠距離及近距離的視力表現均會略有下降"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00150', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '在配戴軟式多焦點鏡片時，良好的鏡片定位及最少滑動，是鏡片呈現最佳視覺表現的重要關鍵，當配戴非 球面鏡片時，定位產生偏心（decentration）時，則主要會產生何種高階像差（higher-orderaberrations）？', '["三叉像差（Trefoil）", "彗星像差（Coma）", "四葉像差（Tetrafoil）", "球面像差（Sphericalaberration）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00151', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '驗配老花隱形眼鏡時，將視標調整至 20/40（0.5）那一行並請患者將用雙手交叉合成一個三角形的空間並 朝視標伸直，此時讓患者用雙眼從三角形中看過去並對準視標的某一個字母，同時請他分別將左眼、右眼 閉上並告知你那個眼睛張開時仍可看到該字母。你在進行何種測試？', '["測試患者的立體視（stereopsis）", "測試患者的主要眼（dominanteye）", "測試患者的對比敏感度（contrastsensitivity）", "測試患者有無斜位或斜視（phoriaortropia）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00152', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列關於軟式交替視覺雙焦（softtranslatingbifocal）隱形眼鏡的敘述，何者錯誤？', '["軟式交替視覺雙焦隱形眼鏡有球面（sphere）與球柱面（toric）鏡片可供選擇", "目前軟式交替視覺雙焦隱形眼鏡可供的選擇比硬式交替視覺雙焦的鏡片少許多", "成功驗配的交替視覺雙焦隱形眼鏡視力品質一般可以比同步視覺設計（simultaneousvision）更好", "此種隱形眼鏡的設計為上面較厚下面較薄，因此患者配戴時比較容易有異物感"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00153', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '在驗光所的檢查區，若患者坐在距離牆面4.5m處，透過鏡中反射的視標來進行視力（visualacuity）量測 檢查時，請問在此條件下，應將螢幕上的史奈倫視力表（Snellen’sChart）之20/20視標字體設定為多大， 患者才可從鏡中驗得較正確的視力值？', '["8.73mm", "6.55mm", "13.10mm", "17.46mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00154', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '一名近視患者同時患有散光，若其散光類型為逆散光（against-the-rule），在霧視之後進行散光鐘面圖（Clock DialChart）檢測，推測其可能覺得那一個方向的線條較清楚？', '["3點鐘方向", "6點鐘方向", "1～2點鐘方向之間", "4～5點鐘方向之間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00155', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '平行光進入散光眼睛聚焦，形成的兩條主焦線（focalline）相關位置與散光分類何者正確？', '["複合性遠視散光前焦線在視網膜上，後焦線在視網膜後", "單純性遠視散光，前焦線在視網膜上，後焦線在視網膜後", "複合性近視散光，前後焦線都在視網膜後", "混合性散光，前後焦線在視網膜前或後同一側"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00156', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關不等像的測試方法，下列敘述何者錯誤？', '["複視影像的大小比較（sizecomparisonofdiplopicimages）", "交替遮蓋法（alternateocclusiontest）", "特維爾測試（Turvilletest）", "馬篤氏桿及筆燈測試（Maddoxrodandpointlightsources）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00157', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列為視標的對數視力值表示方式，何者的視標邊長最大？', '["-0.30", "0", "0.5", "1"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00158', 'optician', 'optician-moex-114-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '自覺驗光檢查時，從單眼（先從右眼）初始球面度數檢查起，若得到患者視力達 0.8，接下來的檢查步驟 為何？', '["換檢查左眼初始球面度數", "做右眼第二次球面度數檢查", "做紅綠檢查右眼球面度數之決定", "做右眼交叉圓柱鏡檢查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "90b2828f3433", "answer_pdf_sha1": "d46f08cf362a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
